--请求穿戴装备
function ModelEquip:OnEquipWearReq(heroId, refIdList, opera)
    local pb = LProtoHelper.CreateProto(LProtoIds.EquipWearReq)
    pb.heroId = heroId

    local equips = pb.equips

    for _, v in ipairs(refIdList) do
        local data = equips:add()
        data.refId = v._refId or v
        data.num = 1
        data.id = v._id or 0
    end

    pb.opera = opera or 0 --0穿戴/一键穿戴 1表示替换
    SendMessage(pb, LProtoIds.EquipWearReq)
end

--请求卸下装备
function ModelEquip:OnEquipUnloadReq(heroId, refIdList)
    local pb = LProtoHelper.CreateProto(LProtoIds.EquipUnloadReq)
    pb.heroId = heroId

    local equips = pb.equips
    for _, v in ipairs(refIdList) do
        local data = equips:add()
        data.refId = v
        data.num = 1
        data.id = gModelHero:GetHeroWearEquipIdByHeroId(heroId, v)
    end

    SendMessage(pb, LProtoIds.EquipUnloadReq)
end

--装备合成
function ModelEquip:OnEquipCompoundReq(equips, rewardEquips, type)
    local pb = LProtoHelper.CreateProto(LProtoIds.EquipCompoundReq)
    for k, v in pairs(equips) do
        local equipInfo = pb.equips:add()
        equipInfo.refId = k
        equipInfo.num = v
    end
    for k, v in pairs(rewardEquips) do
        local equipInfo = pb.rewardEquips:add()
        equipInfo.refId = k
        equipInfo.num = v
    end
    pb.type = type --单个0 一键1
    SendMessage(pb, LProtoIds.EquipCompoundReq)
end

--装备强化 
function ModelEquip:OnEquipStrengthReq(refId, id, expendList)

    local pb = LProtoHelper.CreateProto(LProtoIds.EquipStrengthReq)

    pb.equip.refId = refId
    pb.equip.num = 1
    pb.equip.id = id

    for k, v in pairs(expendList) do
        local data = pb.args:add()

        data.refId = k
        data.num = v
        data.type = 1
    end

    SendMessage(pb, LProtoIds.EquipStrengthReq)
end

function ModelEquip:OnEquipStrengthReq_Refine(refId, id, itemList)

    local pb = LProtoHelper.CreateProto(LProtoIds.EquipStrengthReq)

    pb.equip.refId = refId
    pb.equip.num = 1
    pb.equip.id = id

    for k, v in pairs(itemList) do
        local data = pb.args:add()

        data.refId = v.itemId
        data.num = v.itemNum
        data.type = v.itemType
    end

    pb.refine = true

    SendMessage(pb, LProtoIds.EquipStrengthReq)
end

