--装备分解
function ModelEquip:OnEquipResolveReq(refId, id)
    local equipKey = self:GetEquipListKey(refId, id)
    local equip = self._equipList[equipKey]

    if equip then
        local pb = LProtoHelper.CreateProto(LProtoIds.EquipResolveReq)

        local data = pb.equip:add()
        data.refId = equip:GetRefId()
        data.num = 1
        data.id = equip:GetId()
        SendMessage(pb, LProtoIds.EquipResolveReq)
    else
        printInfoNR2("equip--req--EquipResolveReq", "not equip--refid--" .. tostring(refId))
    end
end
