--返回装备列表
function ModelEquip:OnEquipListResp(pb, ret)
    --装备列表数据下来的时候 进行清理
    self._equipList = {}

    for i = 1, #pb.equips do
        --构建key
        self:ParseEquipChangePb(pb.equips[i])
    end
    FireEvent(EventNames.On_Hero_Change)
    FireEvent(EventNames.On_Equip_Change)
end

--返回装备变化
function ModelEquip:OnEquipChangeResp(pb, ret)
    for i = 1, #pb.change do
        local equipInfo = pb.change[i].equip

        self:ParseEquipChangePb_2(equipInfo)
    end
    FireEvent(EventNames.On_Hero_Change)
    FireEvent(EventNames.On_Equip_Change)
end

function ModelEquip:ParseEquipChangePb(equipPb)
    local key = self:GetEquipListKey(equipPb.refId, equipPb.id)

    if not self._equipList[key] then
        self._equipList[key] = StructEquip:New()
    end

    if not self._newEquipList[key] then
        self._newEquipList[key] = true
    end

    self._equipList[key]:CreateByPb(equipPb)
end

function ModelEquip:ParseEquipChangePb_2(equipPb, syncType)
    --数量0 移除  数量 >0 进行覆盖
    if equipPb.num == 0 then
        local key = self:GetEquipListKey(equipPb.refId, equipPb.id)
        if self._equipList[key] then
            --table.remove(self._equipList, key)
            self._equipList[key] = nil
        end
    else
        self:ParseEquipChangePb(equipPb)
    end
end

--装备表id  -- 唯一id
function ModelEquip:GetEquipListKey(refId, id)
    local key
    if nil == id or tonumber(id) == 0 then
        key = refId
    else
        key = tostring(refId) .. tostring(id)
    end

    return key
end

