function ModelEquip:ParseEquipUpChange(pb, index)
    local result = pb.result

    local equip = StructEquip:New()
    equip:CreateByPb(result)

    local refId = equip:GetRefId()
    local id = equip:GetId()

    local newKey = self:GetEquipListKey(refId, id)

    if self._equipList[newKey] then
        --在背包中
        self._equipList[newKey] = equip
    end
    local data = { equip = equip, index = index }
    FireEvent(self.EventArgs.StrengthChange, data)
end
