--region 配置表的解析 --------------------------------------------------------------------------------
function ModelEquip:ParseEquipUpRef()
    if not self._equipUpRef then
        self._equipUpRef = {}
    end

    if not self._refineLevel then
        self._refineLevel = {}
    end

    if not self._refineMinLevel then
        self._refineMinLevel = {}
    end

    --存储需要的总的经验
    if not self._needUpExp then
        self._needUpExp = {}
    end

    if not self._upEquipRevevanceList then
        self._upEquipRevevanceList = {}
    end

    for k, v in pairs(GameTable.RoleEquipUpRef) do
        if not self._equipUpRef[v.upList] then
            self._equipUpRef[v.upList] = {}
        end

        table.insert(self._equipUpRef[v.upList], v)

        if tonumber(v.lvMax) > 0 then
            if not self._refineLevel[v.upList] then
                self._refineLevel[v.upList] = {}
            end
            --等级的映射表
            if not self._refineMaxLVMapLv then
                self._refineMaxLVMapLv = {}
            end

            if not self._refineMaxLVMapLv[v.upList] then
                self._refineMaxLVMapLv[v.upList] = {}
            end
            self._refineMaxLVMapLv[v.upList][v.lvMax] = v.lv
            --用lv 存储信息 
            self._refineLevel[v.upList][v.lv] = v

            --存储一个最小的信息
            if not self._refineMinLevel[v.upList] then
                self._refineMinLevel[v.upList] = v
            else
                if self._refineMinLevel[v.upList].lv > v.lv then
                    self._refineMinLevel[v.upList] = v
                end
            end

            --记录两个映射
            if not self._upEquipRevevanceList[v.upList] then
                self._upEquipRevevanceList[v.upList] = {}
            end
            self._upEquipRevevanceList[v.upList][v.lvMax] = v.lv
        end
        --最后一个值也进行存储
        if v.upNeedExp == -1 then
            self._refineLevel[v.upList][v.lv] = v
        end
    end

    local totalExp = 0

    for _, v in ipairs(self._equipUpRef) do
        table.sort(v, function(a, b)
            return a.lv < b.lv
        end)

        totalExp = 0

        for i, k in ipairs(v) do
            --排完序 在进行填充totalExp

            if k.upNeedExp > 0 then
                if not self._needUpExp[k.upList] then
                    self._needUpExp[k.upList] = {}
                end

                totalExp = totalExp + k.upNeedExp
                local lvKey = k.lv + 1
                self._needUpExp[k.upList][lvKey] = totalExp
                --把等级1 的数据置成0 
                if k.lv == 1 then
                    self._needUpExp[k.upList][k.lv] = 0
                end
            end

        end

    end

end

function ModelEquip:ParseEquipClassRef()
    self._upGradeEquip = {}
    local tempGrade = {}
    local totalExp = 0
    self._upGradeExp = {}
    for k, v in pairs(GameTable.RoleEquipClassRef) do

        if not self._upGradeEquip[v.classList] then
            self._upGradeEquip[v.classList] = {}
        end

        self._upGradeEquip[v.classList][v.lv] = v

        if not tempGrade[v.classList] then
            tempGrade[v.classList] = {}
        end

        tempGrade[v.classList][v.lv + 1] = v
    end

    for _, v in ipairs(tempGrade) do
        table.sort(v, function(a, b)
            return a.lv < b.lv
        end)
        totalExp = 0
        for i, k in ipairs(v) do
            --排完序 在进行填充totalExp

            if k.upNeedExp > 0 then
                if not self._upGradeExp[k.classList] then
                    self._upGradeExp[k.classList] = {}
                end

                totalExp = totalExp + k.upNeedExp
                local lvKey = k.lv + 1
                self._upGradeExp[k.classList][lvKey] = totalExp
            end
        end
    end
end

--升星  获取关联  和 对应的道具消耗用

-- starCostList  --  key  curRefid  value costItem  --升到当前refid 装备 要的消耗
function ModelEquip:ParseEquipRef()
    for k, v in pairs(GameTable.RoleEquipRef) do
        if not self._starCostList then
            self._starCostList = {}
        end

        if not self._starEquipRevevanceList then
            self._starEquipRevevanceList = {}
        end

        if v.nextStar then
            self._starCostList[v.nextStar] = LxDataHelper.ParseItem_4(v.starCost)

            self._starEquipRevevanceList[v.nextStar] = v.refId
        end
    end
end

function ModelEquip:ParseEquipSuitRef()
    self._equipSuitCache = {}
    for k, v in pairs(GameTable.RoleEquipSuitRef) do
        if not self._equipSuitCache[v.suitList] then
            self._equipSuitCache[v.suitList] = {}
        end

        table.insert(self._equipSuitCache[v.suitList], v)
    end

    for k, v in ipairs(self._equipSuitCache) do
        table.sort(v, function(a, b)
            return a.suitLv < b.suitLv
        end)
    end
end

function ModelEquip:ParseAllConfig()
    self:ParseEquipUpRef()
    self:ParseEquipClassRef()
    self:ParseEquipRef()
    self:ParseEquipSuitRef()
end
