--通过部位获取背包中对应装备
function ModelEquip:GetEquipListByPart(part)
    local list = {}
    for _, v in pairs(self._equipList) do
        if self:GetEquipRefByRefId(v:GetRefId()).type == part and v:GetNum() > 0 then
            table.insert(list, v)
        end
    end
    return list
end

--同部位 背包中是否有比当前更高
function ModelEquip:GetStrongerEquipByPart(equip, part)
    for _, v in pairs(self._equipList) do
        if self:GetEquipRefByRefId(v:GetRefId()).type == part then
            if v:GetScore() > equip:GetScore() and v:GetNum() > 0 then

                return v
            end
        end
    end
    return nil
end

--获取部位的装备 评分最高
function ModelEquip:GetStrongestEquipByPart(part)
    local score, equip = 0, nil
    for _, v in pairs(self._equipList) do
        if self:GetEquipRefByRefId(v:GetRefId()).type == part and v:GetNum() > 0 then
            if v:GetScore() > score then
                score = v:GetScore()
                equip = v
            end
        end
    end
    return equip
end

--一键穿戴 
function ModelEquip:GetAutoWearEquip(heroEquipList)
    -- 缓存两个表 战力最高的套装部分
    local suitEquipCache = {}
    local suitEquipTypeCount = {}

    local tempEquip = {}

    for k, v in pairs(self._equipList) do
        table.insert(tempEquip, v)
    end
    for k, v in pairs(heroEquipList) do
        v.isHeroSelf = true
        table.insert(tempEquip, v)
    end

    --先处理金色品质以上的套装  
    for equipKey, equip in ipairs(tempEquip) do
        --按照套装进行缓存一个key
        local refId = equip:GetRefId()
        --品质>=7 的才进行套装的缓存
        local quality = gModelEquip:GetEquipQualityByRefId(refId)

        if quality >= 7 then
            local equipRef = self:GetEquipRefByRefId(refId)
            local suitKey = equipRef.suitList
            local type = equipRef.type
            if not suitEquipCache[suitKey] then
                suitEquipCache[suitKey] = {}
            end

            if not suitEquipCache[suitKey][type] then
                suitEquipCache[suitKey][type] = {}

                --没有则直接塞入 
                suitEquipCache[suitKey][type] = equip
                --并且对应类型的计数+1
                if not suitEquipTypeCount[suitKey] then
                    suitEquipTypeCount[suitKey] = 1
                else
                    suitEquipTypeCount[suitKey] = suitEquipTypeCount[suitKey] + 1
                end
            else
                --有则进行比较
                local oldScore = suitEquipCache[suitKey][type]:GetScore()
                local newScore = equip:GetScore()
                if newScore > oldScore then
                    suitEquipCache[suitKey][type] = equip


                elseif newScore == oldScore then
                    --如果评分相同 且  suiteKey  type 一致 则优先使用玩家身上的
                    if equip.isHeroSelf then
                        suitEquipCache[suitKey][type] = equip
                    end
                end
            end
        end
    end

    --比较件数
    local curSuitKey = 0

    for suitKey, count in pairs(suitEquipTypeCount) do
        if curSuitKey == 0 then
            curSuitKey = suitKey
        else
            if count > suitEquipTypeCount[curSuitKey] then
                curSuitKey = suitKey

            elseif count == suitEquipTypeCount[curSuitKey] then 
                --判断两边的战力
                local oldSuitPower  = 0
                local newSuitPower = 0
                
                for tempI = 1, 4 do
                    local equip  =suitEquipCache[curSuitKey][tempI]

                    if equip then
                        oldSuitPower=oldSuitPower+ equip:GetScore()
                    end
                end

                for tempI = 1, 4 do
                    local equip  =suitEquipCache[suitKey][tempI]

                    if equip then
                        newSuitPower=newSuitPower+ equip:GetScore()
                    end 
                end
                
                if oldSuitPower < newSuitPower then
                    curSuitKey = suitKey
                end 
                
            end
        end
    end

    -- 拿到填充的列表 suitEquipCache[curSuitKey] 找到没有的被填的类型
    local haveType = {}
    for equipKey, equip in pairs(suitEquipCache[curSuitKey] or {}) do
        local refId = equip:GetRefId()
        local equipRef = self:GetEquipRefByRefId(refId)

        local type = equipRef.type
        haveType[type] = true
    end

    for tempI = 1, 4 do
        if not haveType[tempI] then
            --卸下来时会是空值
            if suitEquipCache[curSuitKey] then
                local tempEquip = self:GetStrongestEquipByPart(tempI)

                if tempEquip and heroEquipList[tempI] and heroEquipList[tempI]:GetScore() >= tempEquip:GetScore() then
                    suitEquipCache[curSuitKey][tempI] = heroEquipList[tempI]
                else
                    suitEquipCache[curSuitKey][tempI] = self:GetStrongestEquipByPart(tempI)
                end
                
            end
        end
    end

    --在比较一次 谁是原本自身的装备
    local refIdList = {}
    local changeList = {}

    for k, v in pairs(suitEquipCache[curSuitKey] or {}) do
        local isChange = false

        local vEquipKey = self:GetEquipListKey(v:GetRefId(), v:GetId())
        local vQuality = gModelEquip:GetEquipQualityByRefId(v:GetRefId())
        local vEquipRef = self:GetEquipRefByRefId(v:GetRefId())
        local vType = vEquipRef.type

        for i, j in pairs(heroEquipList) do

            local jEquipRef = self:GetEquipRefByRefId(j:GetRefId())
            local jType = jEquipRef.type

            if vType == jType then

                local jEquipKey = self:GetEquipListKey(j:GetRefId(), j:GetId())

                --获取下比较的装备 如果两件都是红装就用refid比  如果两件有一键是金装就用equipkey比

                local jQuality = gModelEquip:GetEquipQualityByRefId(j:GetRefId())

                if vQuality >= 7 or jQuality >= 7 then
                    isChange = not (vEquipKey == jEquipKey)
                else
                    isChange = not (v:GetRefId() == j:GetRefId())
                end

                -- 比对完自己的类型就退出去

                
                break
            end
        end

        if isChange then
            table.insert(changeList, v)
        else
            table.insert(refIdList, v)
        end

    end

    local isReplace = #changeList > 0

    if not isReplace then
        --判断下是否空的替换 
        for i = 1, 4 do
            local tempEquip_2
            if not heroEquipList[i] then
                tempEquip_2 = self:GetStrongestEquipByPart(i)
            end

            if tempEquip_2 then
                isReplace = true
                break
            end
        end
    end

    --如果替换是true 且 替换列表是空的 
    if isReplace and (#changeList == 0) then
        for i = 1, 4 do
            local equip = gModelEquip:GetStrongestEquipByPart(i)
            if equip ~= nil then
                -- changelist 与refid互斥
                if not refIdList[i] then
                    --判断下是否是比自身的高
                    if heroEquipList[i] and heroEquipList[i]:GetScore() > equip:GetScore() then

                    else
                        table.insert(changeList, equip)
                    end
                end
            end
        end
    end

    --
    local haveEquipSuitCache =   0
    
    for k,v in pairs(suitEquipCache or {} ) do 
        haveEquipSuitCache= haveEquipSuitCache+1
    end 
    
    
    --如果不是true 那么就每个位置替换一遍  并且没有套装的情况 
    if not isReplace and (haveEquipSuitCache == 0) then
        for i = 1, 4 do
            local equip = gModelEquip:GetStrongestEquipByPart(i)
            if heroEquipList[i] == nil then
                if equip ~= nil then
                    table.insert(changeList, equip)
                    isReplace= true
                end
            else
                if equip ~= nil then
                    if heroEquipList[i]:GetScore() < equip:GetScore() then
                        table.insert(changeList, equip)
                        isReplace= true
                    end
                end
            end
        end
    end

    return changeList, refIdList, isReplace

end

