function ModelEquip:GetEquipCanExtensionRedpoint(equip)
    local refId = equip:GetRefId()
    local equipRef = self:GetEquipRefByRefId(refId)

    --判断装备能否进行强化
    local isSpecial = equipRef.quality >= 7

    if not isSpecial then
        return false
    end

    local isShow = false

    isShow = gModelEquip:GetEquipStrengthRedPoint(equip)

    if not isShow then
        isShow = gModelEquip:GetEquipUpStarRedPoint(equip)
    end

    if not isShow then
        isShow = gModelEquip:GetUpGradeRedPoint(equip)
    end

    return isShow
end

--强化的红点   传入装备
function ModelEquip:GetEquipStrengthRedPoint(equip)
    --获取refid
    local refId = equip:GetRefId()
    local equipRef = self:GetEquipRefByRefId(refId)
    local strengthType = self:GetEquipStrengthType(equipRef)
    local level = equip:GetLevel()
    local equipStrengthRef = gModelEquip:GetEquipStrengthRef(strengthType, level)

    local maxUp = self:GetEquipStrengLimitLv(strengthType)
    local isMax = equip:GetLevel() >= maxUp


    --判断装备能否进行强化
    local isSpecial = equipRef.quality >= 7

    if not isSpecial then
        return false
    end

    --判断是否满级
    if isMax then
        return false
    end

    --判断是否到达上限 上限之后 材料是否足够
    local curRefineId = equip:GetRefineRefId()
    local curRefineRef
    local limitRef
    if curRefineId == 0 then
        limitRef = gModelEquip:GetRefineLevelRef(curRefineId, strengthType)
    else
        curRefineRef = gModelEquip:GetRefineLevelRef(curRefineId, strengthType)
        limitRef = gModelEquip:GetRefineLevelRefByLv(curRefineRef.lvMax, strengthType)
    end

    --判断是否达到了上限
    local isLimitLv = level >= limitRef.lv

    if isLimitLv then
        --判断材料是否够精炼 
        local checkData = {}
        local temp_item = string.split(limitRef.itemCost, ",")
        for k, v in ipairs(temp_item) do
            local item = LxDataHelper.ParseItem_4(v)
            table.insert(checkData, item)
        end
        local haveEnough = true
        for k, v in ipairs(checkData) do
            local num = gModelItem:GetNumByRefId(v.itemId)
            haveEnough = num >= v.itemNum
            if not haveEnough then
                break
            end
        end

        return haveEnough
    else
        --没有达到上限 判断当前的材料是否足够升一级
        --计算所需要的经验
        local numExp = equip:GetExp()
        local nextExp = equipStrengthRef.upNeedExp

        local needExp = nextExp - numExp
        local _, _, isEnough = self:GetOneKeyStrengthExpend(needExp)

        return isEnough
    end
end

--升星的红点
function ModelEquip:GetEquipUpStarRedPoint(equip)
    --获取对应的升星配置
    local refId = equip:GetRefId()
    local equipRef = self:GetEquipRefByRefId(refId)
    local nextRefId = equipRef.nextStar

    --判断装备能否进行强化
    local isSpecial = equipRef.quality >= 7

    if not isSpecial then
        return false
    end

    if nextRefId <= 0 then
        --满星return false
        return false
    end

    --判断材料是否足够
    local checkData = {}
    local temp_item = string.split(equipRef.starCost, ",")
    for k, v in ipairs(temp_item) do
        local item = LxDataHelper.ParseItem_4(v)
        table.insert(checkData, item)
    end

    local haveEnough = true

    for k, v in ipairs(checkData) do
        local num = gModelItem:GetNumByRefId(v.itemId)
        haveEnough = num >= v.itemNum
        if not haveEnough then
            break
        end
    end

    return haveEnough
end

--鑄魂的紅點
function ModelEquip:GetUpGradeRedPoint(equip)
    local refId = equip:GetRefId()
    local equipRef = self:GetEquipRefByRefId(refId)

    --判断装备能否进行强化
    local isSpecial = equipRef.quality >= 7

    if not isSpecial then
        return false
    end

    local classlv = equip:GetGrade()
    local equipClassRef = ModelEquip:GetUpGradeRef(equipRef.type, classlv)

    local curCanUpLv, curLimitLef = self:GetEquipMaxUpGrade(equipRef)

    --先判斷是否能夠升級
    local grade = equip:GetGrade()

    if grade >= curCanUpLv then
        return false
    end

    --判斷材料
    local curExp = equip:GetGradeExp()
    local nextExp = equipClassRef.upNeedExp
    local needExp = nextExp - curExp

    --获取消耗道具
    local costData = self:GetUpGradeExpendItem(equipClassRef)
    local _, _, isCanUp = self:GetUpGradeCost(costData, needExp)
    return isCanUp
end

function ModelEquip:GetUpGradeCost(costData, needExp)
    local curExp = 0
    local useInfo = {}
    for k, v in ipairs(costData) do
        local num = 0
        if v.itemType == LItemTypeConst.TYPE_ITEM then
            num = gModelItem:GetNumByRefId(v.refId) -- 这里取背包数据
        elseif v.itemType == LItemTypeConst.TYPE_EQUIP then
            local equipdata = self:GetEquipStructByRefId(v.refId)
            num = equipdata:GetNum()
        end
        if num > 0 then
            for i = 1, num do
                if curExp >= needExp then
                    return useInfo, curExp, true
                end
                if not useInfo[v.refId] then
                    useInfo[v.refId] = 0
                end
                curExp = v.addExp + curExp
                useInfo[v.refId] = useInfo[v.refId] + 1
            end

        end
    end

    return useInfo, curExp, false
end

