            if maxScore < score then
                maxScore = score
                maxRefId = k
            end
        end
    end
    if wearEquipRefId and maxRefId ~= 0 then
        local wearScore = self:GetScoreByRefId(wearEquipRefId)
        if wearScore > maxScore then
            maxRefId = 0
        end
    end
    return maxRefId
end

