-- 装备合成--

--当前装备能否合成
function ModelEquip:CheckEquipCanCompound(equip)
    local cfg = self:GetEquipRefByRefId(equip:GetRefId())
    local compInfo = {
        maxCompNum = 0,
        costMoney = 0,
        costItem = 0,
        comConst = 0,
        needMoney = 0,
        needEquip = 0
    }
    local compound = cfg.compound
    if compound and compound ~= "" and cfg.composeOrder > 0 then
        local costItem, needMoney, comConst, needEquip
        local s = string.split(compound, ",")
        for i = 1, #s do
            local info = string.split(s[i], "=")
            if tonumber(info[1]) == 1 then
                costItem = tonumber(info[2])
                needMoney = tonumber(info[3])
            elseif tonumber(info[1]) == 3 then
                needEquip = tonumber(info[2])
                comConst = tonumber(info[3])
            end
        end
        local needEquipStruct = self:GetEquipStructByRefId(needEquip)
        local haveMoney = gModelItem:GetNumByRefId(costItem)
        local temp = math.floor(needEquipStruct:GetNum() / comConst)
        local temp2 = math.floor(haveMoney / needMoney)

        compInfo.maxCompNum = math.min(temp, temp2)
        compInfo.costMoney = needMoney * compInfo.maxCompNum
        compInfo.costItem = costItem
        compInfo.comConst = comConst
        compInfo.needMoney = needMoney
        compInfo.needEquip = needEquip
    end
    return compInfo
end

--获取可合成的列表 满足属性
function ModelEquip:GetCanCompoundEquipList4(equipType, equipQualityList)
    local equipList = self._equipList
    if not equipList then
        equipList = {}
        self._equipList = equipList
    end
    local equipRef = {}
    for k, v in pairs(GameTable.RoleEquipRef) do
        local eType = v.type
        local quality = v.quality
        local nextId = v.nextId
        local equipQuality = quality - 1
        if eType == equipType and equipQualityList[equipQuality] then
            table.insert(equipRef, v)
        end
        -- if nextId == 0 and eType == equipType and equipQualityList[5] then
        -- 	table.insert(equipRef,v)
        -- end
    end
    table.sort(equipRef, function(equip1, equip2)
        return equip1.composeOrder < equip2.composeOrder
    end)
    local showList = {}
    local recordList = {}
    local canEquipList = {}
    local haveMoney = gModelItem:GetNumByRefId(101001)
    local payMoney = 0
    local maxRefId = 0
    local isCompound = false
    local payEnough = false            -- 有可合成的
    if haveMoney > 0 then
        for i, v in ipairs(equipRef) do
            local compound = v.compound
            if not string.isempty(compound) then
                local endPay = false
                local refId = v.refId
                compound = string.split(compound, ",")
                local equipCompoundInfo, payInfo = string.split(compound[1], "="), string.split(compound[2], "=")
                local needEquipRefId, needEquipNum, needMoney = tonumber(equipCompoundInfo[2]), tonumber(equipCompoundInfo[3]), tonumber(payInfo[3])
                local bagHaveEquipNum = self:GetEquipStructByRefId(needEquipRefId):GetNum()
                local lastCompoundInfo = showList[needEquipRefId]
                local thisHaveNum = bagHaveEquipNum
                local lastCompoundNum = 0
                if lastCompoundInfo then
                    lastCompoundNum = lastCompoundInfo.num
                    thisHaveNum = bagHaveEquipNum + lastCompoundNum
                end
                local compoundNum = math.floor(thisHaveNum / needEquipNum)
                if compoundNum > 0 then
                    if not payEnough then
                        payEnough = true
                    end
                    local payLastEquipNum = compoundNum * needEquipNum
                    local thisPayMoney = compoundNum * needMoney + payMoney
                    if thisPayMoney > haveMoney then
                        local nowCompoundNum, nowPayMoney = 0, 0
                        for num = 1, compoundNum do
                            local timePay = payMoney + num * needMoney
                            if timePay > haveMoney then
                                endPay = true
                                compoundNum = nowCompoundNum
                                if nowPayMoney ~= 0 then
                                    payMoney = nowPayMoney
                                end
                            else
                                nowCompoundNum, nowPayMoney = num, timePay
                            end
                        end
                    else
                        payMoney = thisPayMoney
                    end

                    payLastEquipNum = compoundNum * needEquipNum
                    if payLastEquipNum >= lastCompoundNum then
                        showList[needEquipRefId] = nil
                    else
                        showList[needEquipRefId].num = lastCompoundNum - payLastEquipNum
                    end

                    -- if payLastEquipNum > bagHaveEquipNum then
                    --     -- 消耗的装备大于背包的数量
                    --     if lastCompoundInfo then
                    --         if not endPay then
                    --             showList[needEquipRefId] = nil
                    --             if payLastEquipNum == lastCompoundNum then
                    --                 recordList[needEquipRefId] = {
                    --                     refId = needEquipRefId,
                    --                     num = lastCompoundNum,
                    --                 }
                    --             else
                    --                 local remain = thisHaveNum - payLastEquipNum
                    --                 recordList[needEquipRefId] = {
                    --                     refId = needEquipRefId,
                    --                     num = remain,
                    --                 }
                    --             end
                    --         end
                    --     end
                    -- elseif payLastEquipNum <= thisHaveNum then
                    --     -- 消耗的装备大于（背包+合成）数量
                    --     if lastCompoundInfo then
                    --         local tempNum = lastCompoundNum - payLastEquipNum
                    --         showList[needEquipRefId] = nil
                    --         if tempNum < 0 then
                    --             recordList[needEquipRefId] = {
                    --                 refId = needEquipRefId,
                    --                 num = lastCompoundNum,
                    --             }
                    --         else
                    --             recordList[needEquipRefId] = {
                    --                 refId = needEquipRefId,
                    --                 num = tempNum,
                    --             }
                    --         end
                    --     end
                    -- end
                end
                if compoundNum > 0 then
                    isCompound = true
                    canEquipList[refId] = compoundNum
                    local equipInfo = {
                        refId = refId,
                        num = compoundNum,
                    }
                    showList[refId] = equipInfo
                    maxRefId = refId
                end
                if endPay then
                    break
                end
            end
        end
    end
    local noEnough = false
    if payMoney == 0 then
        payMoney = -1
        showList = {}
        noEnough = true
    end
    if (not table.isempty(recordList)) and table.isempty(showList) then
        showList = recordList
        if maxRefId ~= 0 then
            for k, v in pairs(showList) do
                if k ~= maxRefId then
                    showList[k] = nil
                end
            end
        end
    end
    return showList, payMoney, canEquipList, noEnough, isCompound, payEnough
end

