function ModelEquip:GetSuitListBySuit(suitLv)
    if not suitLv then
        return
    end
    local ref = {}
    for _, v in pairs(GameTable.RoleEquipSuitRef) do
        if v.suitList == suitLv then
            table.insert(ref, v)
        end
    end

    table.sort(ref, function(a, b)
        return a.suitLv < b.suitLv
    end)
    return ref
end

