function ModelEquip:FindSuitList(list)
    local ret = {}
    for k, v in pairs(list) do
        for _k, _v in pairs(GameTable.RoleEquipSuitRef) do
            local suitList = _v.suitList
            local suitLv = _v.suitLv
            if suitList == v and suitLv == (tonumber(k) - 1) then
                table.insert(ret, _v)
            end
        end
    end
    table.sort(ret, function(equip1, equip2)
        local sort1, sort2 = equip1.suitLv, equip2.suitLv
        local sortList1, sortList2 = equip1.suitList, equip2.suitList
        if sort1 ~= sort2 then
            return sort1 < sort2
        else
            return sortList1 < sortList2
        end
    end)
    return ret
end

