--传入数字获取图片表达的描述
function ModelEquip:GetLevelDesStr(num)
    --只适用三位数的等级
    if (num == 0) then
        return "<sprite index=0>"
    end

    local a = num / 100
    local b = (num % 100) / 10
    local c = (num % 10) % 10

    local listStr = {}
    if a >= 1 then
        table.insert(listStr, "<sprite index=" .. a .. ">")
        table.insert(listStr, "<sprite index=" .. b .. ">")
        table.insert(listStr, "<sprite index=" .. c .. ">")

    else
        if b >= 1 then
            table.insert(listStr, "<sprite index=" .. b .. ">")
            table.insert(listStr, "<sprite index=" .. c .. ">")

        else
            return "<sprite index=" .. c .. ">"
        end
    end

    return table.concat(listStr, "")
end

--获取装备属性部分
function ModelEquip:ParseEquipAttrInfo(attrStr)
    local attrInfo = LxDataHelper.ParseAttr(attrStr)

    if attrInfo.type == 2 then
        attrInfo.value = (attrInfo.value * 100) .. "%"
    end

    local attrName = gModelHero:GetAttributeNameById(attrInfo.refId)
    local icon = gModelHero:GetAttributeIconById(attrInfo.refId)
    attrInfo.attrName = attrName
    attrInfo.icon = icon

    return attrInfo
end

--获取可提升的等级部分
function ModelEquip:GetStrengthUpLevel(exp, curLevel, type)
    local level = 0

    local limitLevel = self:GetEquipStrengLimitLv(type)

    for i = curLevel, limitLevel do
        local ref = gModelEquip:GetEquipStrengthRef(type, i)

        if ref.upNeedExp > 0 then
            exp = exp - ref.upNeedExp
        end

        if exp < 0 or i == limitLevel then
            level = i
            break
        end
    end

    return level
end

--计算提升一级消耗的材料
function ModelEquip:GetOneKeyStrengthExpend(needExp)

    local useItem = gModelItem:GetEquipStrengthItem_1()
    local curExp = 0
    local useInfo = {}
    for k, v in ipairs(useItem) do
        local haveNum = gModelItem:GetNumByRefId(v.refId)-- 这里取背包数据
        if haveNum > 0 then
            for i = 1, haveNum do
                if curExp >= needExp then
                    return useInfo, curExp, true
                end

                if not useInfo[v.refId] then
                    useInfo[v.refId] = 0
                end
                curExp = v.addExp + curExp
                useInfo[v.refId] = useInfo[v.refId] + 1
            end
        end
    end

    --所有都遍历完了还是不够
    return useInfo, curExp, false
end

--获取当前装备等级到限制等级所需要的经验 
function ModelEquip:GetStrengthUpLimitLevelCostExp(curLevel, limitLevel, type)
    local exp = 0
    for i = curLevel, limitLevel - 1 do
        local ref = gModelEquip:GetEquipStrengthRef(type, i)
        exp = exp + ref.upNeedExp
    end

    return exp
end

function ModelEquip:GetGradeUpLimitLevelCostExp(curLevel, limitLevel, type)
    local exp = self._upGradeExp[type][curLevel]

    if not exp then
        exp = 0
    end

    local needExp = self._upGradeExp[type][limitLevel]
    return needExp - exp
end

