--构建classRef的使用道具列表
function ModelEquip:GetUpGradeExpendItem(ref)
    local showList = {}
    local itemList = LxDataHelper.ParseItem(ref.itemCost)

    for k, v in ipairs(itemList) do
        local data = {}
        data.refId = v.itemId
        data.itemType = v.itemType

        if v.itemType == LItemTypeConst.TYPE_EQUIP then
            local equipRef = self:GetEquipRefByRefId(data.refId)
            data.addExp = tonumber(equipRef.classExp)
        elseif v.itemType == LItemTypeConst.TYPE_ITEM then
            local itemRef = gModelItem:GetRefByRefId(data.refId)

            data.addExp = tonumber(itemRef.typeDate)
        end

        table.insert(showList, data)
    end

    return showList
end

function ModelEquip:GetGradeUpLevelLimitLv(type)
    if not self._upGradeEquip then
        self:ParseEquipClassRef()
    end

    --含0级的数据
    local limitLevel = 0

    for k, v in pairs(self._upGradeEquip[type]) do
        limitLevel = limitLevel + 1
    end

    limitLevel = limitLevel - 1

    return limitLevel
end


--获取铸魂可提升的等级部分
function ModelEquip:GetGradeUpLevel(exp, curLevel, type)
    local level = 0

    --含0级的数据
    local limitLevel = #self._upGradeEquip[type]
    limitLevel = limitLevel - 1

    for i = curLevel, limitLevel do
        local ref = gModelEquip:GetUpGradeRef(type, i)

        if ref.upNeedExp > 0 then
            exp = exp - ref.upNeedExp
        end

        if exp < 0 then
            level = i
            break
        end
    end

    if exp >= 0 and level == 0 then
        level = #self._upGradeEquip[type]
    end

    return level
end

--获取当前装备最大的提升lv
function ModelEquip:GetEquipMaxUpGrade(ref)
    if not self._upGradeEquip then
        self:ParseEquipClassRef()
    end

    local list = self._upGradeEquip[ref.type]

    local lv = 0
    local resultref = self._upGradeEquip[ref.type][0]
    for k, v in pairs(list) do
        if v.upNeedStar > 0 then
            if ref.star >= v.upNeedStar then
                if lv < v.lv then
                    lv = v.lv


                end
            end
        end
    end
    local result = 0

    if lv > 0 then
        result = lv + 1
        resultref = self._upGradeEquip[ref.type][result]
    else
        result = 0
    end

    return result, resultref
end

--获取当前装备分解的材料
function ModelEquip:GetEquipBreakBackItem(equip)
    local refId = equip:GetRefId()
    local ref = gModelEquip:GetEquipRefByRefId(refId)

    self.backItems = {}

    --基础的返回
    local item = LxDataHelper.ParseItem_4(ref.resolve)
    table.insert(self.backItems, item)

    --获取星星的消耗
    self:InsertStarCostItem(refId)

    --强化经验返回
    local strengthType = self:GetEquipStrengthType(ref)

    local level = equip:GetLevel()
    local totalExp = self._needUpExp[strengthType][level] or 0
    totalExp = totalExp + equip:GetExp()
    if totalExp and totalExp > 0 then
        --转为经验道具    
        self:InitStrengthExpItem(totalExp)
    end

    -- 精炼道具
    local refineRefId = equip:GetRefineRefId()

    self:InsertRefineCostItem(refineRefId, strengthType)

    --铸魂道具
    local gradeLevle = equip:GetGrade()
    local totalGradeExp = self._upGradeExp[ref.classList][gradeLevle] or 0
    totalGradeExp = totalGradeExp + equip:GetGradeExp()
    self:InitGradeExpItem(totalGradeExp)

    return self.backItems
end

--星星材料进行递归填充 
function ModelEquip:InsertStarCostItem(refId)
    if not refId then
        return
    end

    --获取星星的消耗
    local starCostItem = self._starCostList[refId]

    if not starCostItem then
        return
    end

    self:InsertBackItem(starCostItem)

    --拿下上一级的部分
    local lastRefId = self._starEquipRevevanceList[refId]

    if lastRefId and lastRefId > 0 then
        self:InsertStarCostItem(lastRefId)
    end
end

--精炼材料填充
function ModelEquip:InsertRefineCostItem(refineRefId, strengthType)
    if (not refineRefId) or (refineRefId == 0) then
        return
    end

    local refineRef = self:GetRefineLevelRef(refineRefId, strengthType)

    local costItem = LxDataHelper.ParseItem(refineRef.itemCost)

    for k, v in ipairs(costItem) do
        self:InsertBackItem(v)
    end

    local nextLV = self._refineMaxLVMapLv[strengthType][refineRef.lv]

    if nextLV and nextLV > 0 then
        local ref = self._refineLevel[strengthType][nextLV]

        if ref then
            self:InsertRefineCostItem(ref.refId, strengthType)
        end

    end
end

--精炼经验材料
function ModelEquip:InitStrengthExpItem(exp)
    --  156道具
    local itemDatas = gModelItem:GetEquipStrengthItem_1()
    local calcuExp = exp
    local expItem = {}

    table.sort(itemDatas, function(a, b)
        return tonumber(a.addExp) > tonumber(b.addExp)
    end)

    for k, v in ipairs(itemDatas) do
        if calcuExp > 0 then

            local data = {}
            data.itemType = v.itemType
            data.itemId = v.refId
            data.itemNum = 0
            data.isShowEff = 0

            local num = math.floor(calcuExp / v.addExp)
            data.itemNum = num

            local curExp = num * v.addExp
            calcuExp = calcuExp - curExp

            if num > 0 then
                table.insert(expItem, data)
            end

        end
    end

    for k, v in ipairs(expItem) do
        self:InsertBackItem(v)
    end
end

function ModelEquip:InitGradeExpItem(exp)
    --这里只处理一个道具  204021
    local itemRef = gModelItem:GetRefByRefId(204021)
    local addExp = tonumber(itemRef.typeDate)

    local data = {}
    data.itemType = 1
    data.itemId = 204021
    data.itemNum = 0
    data.isShowEff = 0

    local num = math.floor(exp / addExp)
    data.itemNum = num
    if num > 0 then
        self:InsertBackItem(data)
    end
end

--相同的道具要进行合并
function ModelEquip:InsertBackItem(item)
    for k, v in ipairs(self.backItems) do
        if v. itemId == item.itemId then
            v.itemNum = v.itemNum + item.itemNum
            return
        end
    end

    --没有叠加则进行插入
    table.insert(self.backItems, item)
end

--强化等级和铸魂的战力
function ModelEquip:GetStrengthAndRefineScore(equipRefId, sid, level, grade, refineID)
    local lvScore = 0
    local gradeScore = 0
    local refineScore = 0

    local equipRef = self:GetEquipRefByRefId(equipRefId)

    if equipRef.quality < 7 then
        return lvScore, gradeScore, refineScore
    end

    if level > 0 then
        local strengthType = gModelEquip:GetEquipStrengthType(equipRef)
        local equipUpRef = self:GetEquipStrengthRef(strengthType, level)
        lvScore = equipUpRef.score1
    end

    if refineID > 0 then
        local equipUpRef = GameTable.RoleEquipUpRef[refineID]
        refineScore = equipUpRef.score2
    end

    if grade > 0 then
        local equipClassRef = ModelEquip:GetUpGradeRef(equipRef.classList, grade)
        gradeScore = equipClassRef.score
    end
    return lvScore, gradeScore, refineScore
end

--计算当前的道具数量 经验差值  return 当前道具的最大消耗量  costItemInfo  -- addExp  remainNum  -- 装备强化部分
function ModelEquip:GetMaxCostItemNum_Strength(curLev, limitLv, curExp, strengthType, costItemInfo, remainNum)
    local exp = self:GetStrengthUpLimitLevelCostExp(curLev, limitLv, strengthType)

    if curExp > 0 then
        exp = exp - curExp
    end

    local addExp = tonumber(costItemInfo.addExp)
    local useNum_1 = math.floor(exp / addExp)
    local useNum_2 = exp / addExp
    local useNum = useNum_1 < useNum_2 and (useNum_1 + 1) or useNum_1

    local result
    if useNum > remainNum then
        result = remainNum
    else
        result = useNum
    end

    return result
end

--计算当前的道具数量 经验差值  return 当前道具的最大消耗量  costItemInfo  -- addExp  remainNum  -- 装备铸魂部分
function ModelEquip:GetMaxCostItemNum_UpGrade(curLev, limitLv, curExp, strengthType, costItemInfo, remainNum)
    local exp = self:GetGradeUpLimitLevelCostExp(curLev, limitLv, strengthType)

    if curExp > 0 then
        exp = exp - curExp
    end
    printInfoN2("----", "---")

    local addExp = tonumber(costItemInfo.addExp)
    local useNum_1 = math.floor(exp / addExp)
    local useNum_2 = exp / addExp
    local useNum = useNum_1 < useNum_2 and (useNum_1 + 1) or useNum_1

    local result
    if useNum > remainNum then
        result = remainNum
    else
        result = useNum
    end

    return result
end
